// Detect brute-force / password-spray patterns in a batch of Okta System Log
// style auth events. Responds immediately to the caller (webhook is 'onReceived')
// so the approval wait later never blocks the event source.
const body = $json.body ?? $json;
const events = Array.isArray(body) ? body : (body.events ?? [body]);

const norm = events.map(e => ({
  type: e.eventType ?? '',
  result: e.outcome?.result ?? e.result ?? '',
  user: e.actor?.alternateId ?? e.user ?? 'unknown',
  ip: e.client?.ipAddress ?? e.src_ip ?? 'unknown',
  geo: e.client?.geographicalContext?.country ?? e.geo ?? null,
  time: e.published ?? e.timestamp ?? null,
})).filter(e => e.type.startsWith('user.authentication') || e.type.startsWith('user.session'));

const failures = norm.filter(e => e.result === 'FAILURE');
const successes = norm.filter(e => e.result === 'SUCCESS');

// Group failures by user+ip and by ip
const byUserIp = {}, byIp = {};
for (const f of failures) {
  const k = `${f.user}|${f.ip}`;
  byUserIp[k] = (byUserIp[k] ?? 0) + 1;
  (byIp[f.ip] = byIp[f.ip] ?? new Set()).add(f.user);
}

const BRUTE_THRESHOLD = 10;   // failures against one account from one IP
const SPRAY_THRESHOLD = 5;    // distinct accounts targeted from one IP

let detection = { pattern_detected: false };

const bruteHit = Object.entries(byUserIp).find(([, n]) => n >= BRUTE_THRESHOLD);
const sprayHit = Object.entries(byIp).find(([, users]) => users.size >= SPRAY_THRESHOLD);

if (bruteHit || sprayHit) {
  const [key, count] = bruteHit ?? [null, 0];
  const [user, ip] = bruteHit ? key.split('|') : [null, sprayHit[0]];
  const targetIp = bruteHit ? ip : sprayHit[0];
  const successAfter = successes.some(s => s.ip === targetIp);
  detection = {
    pattern_detected: true,
    pattern_type: bruteHit ? 'brute_force' : 'password_spray',
    user: user ?? [...(byIp[targetIp] ?? [])].join(', '),
    primary_user: user ?? [...(byIp[targetIp] ?? [])][0] ?? 'unknown',
    src_ip: targetIp,
    src_geo: failures.find(f => f.ip === targetIp)?.geo ?? null,
    failure_count: bruteHit ? count : failures.filter(f => f.ip === targetIp).length,
    distinct_users_targeted: byIp[targetIp]?.size ?? 1,
    success_after_failures: successAfter,
    severity: successAfter ? 'critical' : 'high',
    detection_id: `bf-${Date.now()}`,
    window_events: norm.length,
  };
}

return [{ json: detection }];

