// Validate LLM output; anything malformed becomes 'uncertain' (=> analyst review path).
const detection = $('Detect Brute-Force Pattern').first().json;
let out = $json.message?.content ?? $json.output ?? {};
if (typeof out === 'string') {
  try { out = JSON.parse((out.match(/\{[\s\S]*\}/) || ['{}'])[0]); } catch (e) { out = {}; }
}
const allowed = ['likely_attack', 'likely_benign', 'uncertain'];
const valid = allowed.includes(out.assessment);
// Strip Slack-active characters from LLM prose (injection defense).
const clean = s => String(s ?? '').replace(/[<>@]/g, '').slice(0, 600);
return { json: {
  ...detection,
  assessment: valid ? out.assessment : 'uncertain',
  confidence: valid ? Math.min(100, Math.max(0, Number(out.confidence) || 0)) : 0,
  rationale: valid ? clean(out.rationale) : 'LLM output failed validation (or the LLM call failed) — routed to analyst review.',
  containment_recommended: valid ? !!out.containment_recommended : false,
  notes_for_analyst: clean(out.notes_for_analyst ?? ''),
} };

// Fail-safe evaluation: containment happens ONLY on an explicit approve.
// Timeout (no resume call) or any other value => deny.
const detection = $('Parse Assessment').first().json;
const q = $json.query ?? {};
const approved = q.action === 'approve';
return { json: {
  ...detection,
  approved,
  approver: q.approver ?? null,
  decision_source: q.action ? `resume:${q.action}` : 'timeout',
  decided_at: new Date().toISOString(),
} };

